const j=$json; let txt='';
if (typeof j==='string') txt=j;
else if (j.text) txt=j.text;
else if (typeof j.content==='string') txt=j.content;
else if (j.content && j.content.parts && j.content.parts[0] && j.content.parts[0].text) txt=j.content.parts.map(p=>p.text||'').join('');
